import{_ as a,o as e,c as r,ag as d}from"./chunks/framework.CQYuu_FX.js";const b=JSON.parse('{"title":"プリンタ連携","description":"","frontmatter":{"title":"プリンタ連携"},"headers":[],"relativePath":"tenant/26-printer.md","filePath":"tenant/26-printer.md"}'),i={name:"tenant/26-printer.md"};function l(n,t,o,h,s,c){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="_26-プリンタ連携" tabindex="-1">26. プリンタ連携 <a class="header-anchor" href="#_26-プリンタ連携" aria-label="Permalink to &quot;26. プリンタ連携&quot;">​</a></h1><p>プリンタ連携では、レシート、領収書、キッチン伝票などの印刷を行います。営業開始前に必ずテスト印刷を実施してください。</p><h2 id="対応する印刷物" tabindex="-1">対応する印刷物 <a class="header-anchor" href="#対応する印刷物" aria-label="Permalink to &quot;対応する印刷物&quot;">​</a></h2><table tabindex="0"><thead><tr><th>印刷物</th><th>主な利用場面</th></tr></thead><tbody><tr><td>レシート</td><td>会計完了時</td></tr><tr><td>領収書</td><td>お客様から依頼されたとき</td></tr><tr><td>キッチン伝票</td><td>厨房で紙伝票を併用する場合</td></tr><tr><td>QRコード</td><td>テーブル、テイクアウト、予約案内</td></tr></tbody></table><h2 id="設定前に確認すること" tabindex="-1">設定前に確認すること <a class="header-anchor" href="#設定前に確認すること" aria-label="Permalink to &quot;設定前に確認すること&quot;">​</a></h2><ul><li>プリンタの電源が入っていること</li><li>用紙が入っていること</li><li>店舗ネットワークにつながっていること</li><li>レジ端末からプリンタに接続できること</li><li>レシートに表示する店舗名、住所、登録番号が正しいこと</li></ul><h2 id="テスト印刷" tabindex="-1">テスト印刷 <a class="header-anchor" href="#テスト印刷" aria-label="Permalink to &quot;テスト印刷&quot;">​</a></h2><p>設定後は、レシート、領収書、キッチン伝票をそれぞれテスト印刷してください。文字化け、余白、用紙幅、ロゴ、金額表示を確認します。</p><h2 id="営業中の注意" tabindex="-1">営業中の注意 <a class="header-anchor" href="#営業中の注意" aria-label="Permalink to &quot;営業中の注意&quot;">​</a></h2><ul><li>用紙切れに備えて予備ロールを用意してください。</li><li>プリンタの電源やネットワークが切れないようにしてください。</li><li>印刷できない場合の手書き対応を店舗内で決めておいてください。</li></ul><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>印刷されない</td><td>電源、用紙、ネットワーク、プリンタ選択を確認してください。</td></tr><tr><td>文字化けする</td><td>プリンタ設定と用紙幅を確認してください。</td></tr><tr><td>領収書の内容が違う</td><td>店舗情報と領収書設定を確認してください。</td></tr><tr><td>キッチン伝票が出ない</td><td>対象商品と印刷先を確認してください。</td></tr></tbody></table>',12)])])}const u=a(i,[["render",l]]);export{b as __pageData,u as default};
